// // This is a 2-to-1 multiplexer that selects between two input signals i0 and i1 based on the selection signal sel. When sel is 0, the output out follows i1; when sel is 1, the output follows i0.
module top_module(i0, i1, sel, out	);parameter SIZE = 1;

	input  [SIZE-1:0] i0;
	input  [SIZE-1:0] i1;
	input             sel;
	output [SIZE-1:0] out;	

	assign out = (sel ? i1 : i0);endmodule
